142→    fun downloadPdf(url: String, smsId: Long, fileName: String? = null, cookies: String? = null) {
143→        viewModelScope.launch {
144→            val result = pdfDownloader.download(url, fileName, cookies)
145→            when (result) {
146→                is DownloadResult.Success -> {
147→                    val pdf = PdfDocumentEntity(
148→                        smsId = smsId,
149→                        fileName = result.fileName,
150→                        filePath = result.filePath,
151→                        fileSize = result.fileSize,
152→                        fileMd5 = result.fileMd5,
153→                        downloadedAt = System.currentTimeMillis(),
154→                        isSubpoena = false
155→                    )
156→                    val pdfId = repo.insertPdf(pdf)
157→                    if (pdfId > 0) {
158→                        _uiState.update { it.copy(downloadCount = it.downloadCount + 1) }
159→                        _downloadEvent.emit("已保存: ${result.fileName}")
160→                        tryParseAndSync(pdfId, result.filePath, smsId)
161→                        refreshPdfList()
162→                    } else {
163→                        _downloadEvent.emit("文件已存在: ${result.fileName}")
164→                    }
165→                }
166→                is DownloadResult.Error -> {
167→                    _downloadEvent.emit("下载失败: ${result.message}")
168→                }
169→            }
170→        }
171→    }
