173→    private suspend fun tryParseAndSync(pdfId: Long, filePath: String, smsId: Long) {
174→        val info = pdfParser.parseSubpoena(filePath) ?: return
175→        val pdf = repo.getPdfById(pdfId) ?: return
176→
177→        // 判断是否为传票：有开庭时间或文件名/内容含传票关键词
178→        val isSubpoena = info.hearingTime != null ||
179→            pdf.fileName.contains("传票") ||
180→            info.defendant != null
181→
182→        val hearingDesc = buildString {
183→            if (info.courtName != null) append("法院: ${info.courtName}\n")
184→            if (info.defendant != null) append("被传唤人: ${info.defendant}\n")
185→            if (info.handler != null) append("承办人: ${info.handler}\n")
186→            if (info.location != null) append("地点: ${info.location}")
187→            if (info.phone != null) append("\n电话: ${info.phone}")
188→        }.takeIf { it.isNotBlank() }
189→
190→        if (info.hearingTime != null && info.caseNumber != null) {
191→            val eventId = calendarSync.syncHearing(
192→                caseNumber = info.caseNumber,
193→                courtName = info.courtName,
194→                hearingTime = info.hearingTime,
195→                defendant = info.defendant,
196→                handler = info.handler,
197→                location = info.location,
198→                phone = info.phone,
199→                caseType = info.caseType
200→            )
201→            repo.updatePdf(pdf.copy(isSubpoena = isSubpoena, hearingInfo = hearingDesc, calendarEventId = eventId))
202→            if (eventId != null) {
203→                _downloadEvent.emit("📅 已同步到日历")
204→            }
205→        } else if (hearingDesc != null || isSubpoena) {
206→            repo.updatePdf(pdf.copy(isSubpoena = isSubpoena, hearingInfo = hearingDesc))
207→        }
208→    }
