 3→import android.webkit.WebResourceRequest
 4→import android.webkit.WebResourceResponse
 5→import android.webkit.WebView
 6→import android.webkit.WebViewClient
 7→
 8→class CourtWebViewClient(
 9→    private val onPdfDetected: (url: String) -> Unit,
10→    private val onPageLoaded: () -> Unit
11→) : WebViewClient() {
12→
13→    private val detectedUrls = mutableSetOf<String>()
14→
15→    private fun notifyPdf(url: String) {
16→        val key = url.substringBefore("?")
17→        if (detectedUrls.add(key)) onPdfDetected(url)
18→    }
19→
20→    override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
21→        val url = request?.url?.toString() ?: return false
22→        if (isPdfUrl(url)) {
23→            notifyPdf(url)
24→            return true
25→        }
26→        return false
27→    }
28→
29→    override fun shouldInterceptRequest(view: WebView?, request: WebResourceRequest?): WebResourceResponse? {
30→        val url = request?.url?.toString() ?: return null
31→        if (isPdfUrl(url) && request.method.equals("GET", ignoreCase = true)) {
32→            view?.post { notifyPdf(url) }
33→            return null
34→        }
35→        return null
36→    }
37→
38→    override fun onPageFinished(view: WebView?, url: String?) {
39→        super.onPageFinished(view, url)
40→        onPageLoaded()
41→        // 注入JS：拦截通过 window.open 或 JS 触发的 PDF 链接
42→        view?.evaluateJavascript("""
43→            (function() {
44→                if (window._courtPdfHooked) return;
45→                window._courtPdfHooked = true;
46→                document.addEventListener('click', function(e) {
47→                    var el = e.target;
48→                    while (el && el.tagName !== 'A') el = el.parentElement;
49→                    if (el && el.href) {
50→                        var href = el.href.toLowerCase();
51→                        if (href.endsWith('.pdf') || href.indexOf('.pdf?') !== -1
52→                            || href.indexOf('getpdf') !== -1 || href.indexOf('download') !== -1
53→                            || href.indexOf('文书') !== -1) {
54→                            window.location.href = el.href;
55→                        }
56→                    }
57→                }, true);
58→                var origOpen = window.open;
59→                window.open = function(url) {
60→                    if (url) window.location.href = url;
61→                    return null;
62→                };
63→            })();
64→        """.trimIndent(), null)
65→    }
66→
67→    private fun isPdfUrl(url: String): Boolean {
68→        val lower = url.lowercase()
69→        return lower.endsWith(".pdf") || lower.contains(".pdf?")
70→            || lower.contains("getpdf") || lower.contains("download") && lower.contains("pdf")
71→    }
72→}
